if (NavStars.getNavStarsMarks()) {
    core.debug("Navigational stars are visible");
} else {
    NavStars.setNavStarsMarks(true);
}

// Show navigational stars
NavStars.setNavStarsMarks(true);

// Hide navigational stars
NavStars.setNavStarsMarks(false);

var set = NavStars.getCurrentNavigationalStarsSet();
if (set === 0) core.debug("Anglo-American set (The Nautical Almanac)");
else if (set === 7) core.debug("German set (Nautisches Jahrbuch)");
else if (set === 14) core.debug("Apollo Alignment Star List");

// Use Anglo-American set (The Nautical Almanac)
NavStars.setCurrentNavigationalStarsSet(0);

// Use Apollo set
NavStars.setCurrentNavigationalStarsSet(14);

// Use Meade LX200 set
NavStars.setCurrentNavigationalStarsSet(9);

if (NavStars.getEnableAtStartup()) {
    core.debug("Navigational stars will appear on next startup");
}

// Enable on next startup
NavStars.setEnableAtStartup(true);

// Disable on next startup
NavStars.setEnableAtStartup(false);

if (NavStars.getHighlightWhenVisible()) {
    core.debug("Navigational stars are highlighted when visible");
}

// Highlight navigational stars when visible
NavStars.setHighlightWhenVisible(true);

// Use normal appearance for all stars
NavStars.setHighlightWhenVisible(false);

if (NavStars.getLimitInfoToNavStars()) {
    core.debug("Navigational info shown only for navigational stars");
}

// Show navigational data only for navigational stars
NavStars.setLimitInfoToNavStars(true);

// Show navigational data for all objects
NavStars.setLimitInfoToNavStars(false);

if (NavStars.getUpperLimb()) {
    core.debug("Moon calculations use upper limb");
}

// Use upper limb for Moon calculations
NavStars.setUpperLimb(true);

// Use center for Moon calculations
NavStars.setUpperLimb(false);

if (NavStars.getTabulatedDisplay()) {
    core.debug("Using Nautical Almanac tabulated format");
}

// Use Nautical Almanac tabulated format
NavStars.setTabulatedDisplay(true);

// Use standard paired lines format
NavStars.setTabulatedDisplay(false);

if (NavStars.getShowExtraDecimals()) {
    core.debug("Extra precision mode enabled");
}

// Enable high precision mode
NavStars.setShowExtraDecimals(true);

// Use standard precision
NavStars.setShowExtraDecimals(false);

if (NavStars.getFlagUseUTCTime()) {
    core.debug("UTC time used for calculations");
}

// Use UTC for Nautical Almanac style calculations
NavStars.setFlagUseUTCTime(true);

// Use local time
NavStars.setFlagUseUTCTime(false);

var stars = NavStars.getStarsNumbers();
core.debug("Navigational stars count: " + stars.length);
for (var i = 0; i < Math.min(5, stars.length); i++) {
    core.debug("Hip: " + stars[i]);
}

// Reset all navigational stars settings to defaults
NavStars.restoreDefaultConfiguration();
core.debug("Navigational Stars settings restored");

// Save current settings
NavStars.saveConfiguration();
core.debug("Navigational Stars settings saved");

NavStars.setCurrentNavigationalStarsSetKey("Apollo");
NavStars.populateNavigationalStarsSet();
core.debug("Apollo navigational stars populated");

if (NavStars.isPermittedObject("Sirius")) {
    core.debug("Sirius is a navigational star");
}
if (NavStars.isPermittedObject("Sun")) {
    core.debug("Sun is permitted for navigational info");
}
